    /**
     * 按横坐标整理图表数据，确保后续插值稳定。
     */
    static Series sortByX(double[] xs, double[] ys) {
        MathArrays.checkEqualLength(xs, ys);
        double[] sortedXs = xs.clone();
        double[] sortedYs = ys.clone();
        MathArrays.sortInPlace(sortedXs, sortedYs);
        return new Series(sortedXs, sortedYs);
    }

